import{_ as t,o as n,c as a,a0 as o}from"./chunks/framework.jwovEGr5.js";const i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",d=JSON.parse('{"title":"Payment Instructions & Completing a Request","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/payment-instructions.md","filePath":"subscriptions/payment-instructions.md"}'),r={name:"subscriptions/payment-instructions.md"};function s(h,e,l,u,m,p){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="payment-instructions-completing-a-request" tabindex="-1">Payment Instructions &amp; Completing a Request <a class="header-anchor" href="#payment-instructions-completing-a-request" aria-label="Permalink to &quot;Payment Instructions &amp; Completing a Request&quot;">​</a></h1><p>Once you&#39;ve <a href="./request-subscription.html">requested a subscription</a>, payment (if any) is arranged <strong>manually</strong> through the request&#39;s message thread. This page explains how that works and what to expect.</p><h2 id="there-is-no-online-checkout" tabindex="-1">There is no online checkout <a class="header-anchor" href="#there-is-no-online-checkout" aria-label="Permalink to &quot;There is no online checkout&quot;">​</a></h2><blockquote><p><strong>The app does not process payments.</strong> There&#39;s no card form, no checkout, and no automatic billing inside the tracker. Nobody is asked to enter payment details into the app. Everything happens through the <strong>message thread</strong> on your request and whatever <strong>payment or donation links</strong> the Supreme Admin has set up.</p></blockquote><p>This keeps money handling outside the app entirely — you pay through the method your admin tells you to use, not through a page here.</p><h2 id="how-it-flows" tabindex="-1">How it flows <a class="header-anchor" href="#how-it-flows" aria-label="Permalink to &quot;How it flows&quot;">​</a></h2><ol><li>You submit a request (see <a href="./request-subscription.html">Request a Subscription</a>). It starts as <strong>Pending</strong>.</li><li>The Supreme Admin reviews it and, if payment is needed, <strong>sends payment instructions</strong>. Your request moves to <strong>Awaiting payment</strong>.</li><li>You read the instructions in the thread, pay by the method described, and <strong>reply</strong> to confirm (for example, &quot;Paid — sent via PayPal&quot;).</li><li>The admin verifies and marks the request <strong>Completed</strong>. Your <a href="./../getting-started/glossary.html#plan">plan</a> activates and your <a href="./effective-plan.html">effective plan</a> updates.</li></ol><p><img src="'+i+'" alt="Payment instructions in the request thread"></p><h2 id="reading-the-payment-instructions" tabindex="-1">Reading the payment instructions <a class="header-anchor" href="#reading-the-payment-instructions" aria-label="Permalink to &quot;Reading the payment instructions&quot;">​</a></h2><p>The admin&#39;s instructions arrive as a message in your request thread. They&#39;ll tell you <strong>how much</strong>, <strong>how to pay</strong>, and <strong>how to confirm</strong>. Alongside them you may see <strong>support links</strong> — things like a PayPal or Revolut link, a Discord invite, or crypto addresses — that the Supreme Admin configured for the platform. Use whichever method the instructions point you to.</p><blockquote><p>Where do those links come from? A Supreme Admin sets them up. That setup is covered in <a href="./../admin/support-links.html">Configure Support Links</a> <em>(admin section)</em>. As a requester, you just use the links you&#39;re given.</p></blockquote><h2 id="confirming-payment" tabindex="-1">Confirming payment <a class="header-anchor" href="#confirming-payment" aria-label="Permalink to &quot;Confirming payment&quot;">​</a></h2><p>After you&#39;ve paid, <strong>reply in the thread</strong> to let the admin know. Include anything that helps them match your payment (the method you used, a reference, the date). The admin then completes the request on their side — you don&#39;t activate the plan yourself.</p><h2 id="after-completion" tabindex="-1">After completion <a class="header-anchor" href="#after-completion" aria-label="Permalink to &quot;After completion&quot;">​</a></h2><p>When the request is marked <strong>Completed</strong>:</p><ul><li>The plan is assigned and becomes active.</li><li>Your Subscription &amp; Usage panel shows the new plan and higher limits.</li><li>Premium features unlock (see <a href="./premium-features.html">Premium Features</a>).</li></ul><p>If something looks wrong after completion — the wrong plan, missing features — reply in the same thread; the admin can adjust.</p><h2 id="if-you-change-your-mind" tabindex="-1">If you change your mind <a class="header-anchor" href="#if-you-change-your-mind" aria-label="Permalink to &quot;If you change your mind&quot;">​</a></h2><p>While a request is still open (pending or awaiting payment), you can <strong>cancel</strong> it. If you&#39;ve already paid, don&#39;t cancel — talk to the admin in the thread instead.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./request-subscription.html">Request a Subscription</a> — the step before this one.</li><li><a href="./effective-plan.html">Which Plan Applies to You</a> — confirming your new plan took effect.</li><li><a href="./quota-warnings.html">Quota Warnings</a> — making the most of your new limits.</li></ul>',21)])])}const g=t(r,[["render",s]]);export{d as __pageData,g as default};
